UPDATE PROVINCE_BOUNDARY
SET PROVINCE_ABBREVIATION = REPLACE(PROVINCE_ABBREVIATION, chr(10), '')
WHERE PROVINCE_ABBREVIATION LIKE '%' || chr(10) || '%';
